mapper.select:
SELECT id, template_code AS templateCode, template_name AS templateName, title_template AS titleTemplate, content_template AS contentTemplate, channels, recipient_type AS recipientType, status, create_time AS createTime FROM sys_notice_template
deleted = 0
AND (template_code LIKE CONCAT('%', #{query.keyword}, '%') OR template_name LIKE CONCAT('%', #{query.keyword}, '%'))
AND recipient_type = #{query.recipientType}
AND status = #{query.status}
ORDER BY create_time DESC
